queries.sparql:
PREFIX : <http://ambrosia.example.org/education#>
PREFIX p: <http://ambrosia.example.org/education/prop#>
PREFIX xsd: <http://www.w3.org/2001/XMLSchema#>
SELECT ?title ?softwarename WHERE {
  ?c a :Courses .
  ?tas a :Textbooks_and_Software .
  ?tas p:hasCourses ?c .
  OPTIONAL { ?c p:Title ?title . }
  OPTIONAL { ?tas p:SoftwareName ?softwarename . }
}

